function setMyLocationFromClick(page, clientX, clientY){
  const frame=document.getElementById(`frame-${page}`);
  const map=document.getElementById(`map-${page}`);
  const rect = map.getBoundingClientRect();
  const scale = (map.style.transform ? parseFloat((map.style.transform.match(/scale\(([^)]+)\)/)||[0,1])[1]) : 1);
  const x = (clientX - rect.left + frame.scrollLeft) / scale;
  const y = (clientY - rect.top + frame.scrollTop) / scale;

  const payload = routePages[page];
  if(payload){
    const snapped = snapToCorridorCenter(page, pointToGrid(page, x, y), 6);
    if(snapped){
      myLocation = {page, gx: snapped.gx, gy: snapped.gy};
    }else{
      alert('복도 색 영역 위를 눌러 주세요.');
      return;
    }
  }else{
    myLocation = {page, x, y};
  }
  settingMyLocation = false;
  renderLocationButtons();
  persistMyLocation();
  renderOverlays();
  renderMobileDock();
  closePanelOnMobile();
}
